{
  "name": "@ifi/pi-spec",
  "version": "0.4.4",
  "description": "Native spec-kit workflow for pi with a /spec command, TypeScript scaffolding, and spec-driven prompts.",
  "type": "module",
  "keywords": [
    "pi-package",
    "pi",
    "pi-coding-agent",
    "spec",
    "spec-driven-development",
    "requirements",
    "workflow"
  ],
  "pi": {
    "extensions": [
      "./extension/index.ts"
    ]
  },
  "exports": {
    "./package.json": "./package.json"
  },
  "files": [
    "extension",
    "README.md",
    "!**/*.test.ts"
  ],
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/ifiokjr/oh-pi.git",
    "directory": "packages/spec"
  },
  "homepage": "https://github.com/ifiokjr/oh-pi/tree/main/packages/spec",
  "bugs": {
    "url": "https://github.com/ifiokjr/oh-pi/issues"
  },
  "scripts": {
    "build": "pnpm run typecheck && pnpm run test:worktree",
    "typecheck": "tsgo --project ./tsconfig.json --noEmit",
    "test:worktree": "vitest run --config ./vitest.worktree.config.ts"
  },
  "peerDependencies": {
    "@fink-andreas/pi-linear-tools": "*",
    "@mariozechner/pi-agent-core": ">=0.56.1",
    "@mariozechner/pi-ai": ">=0.56.1",
    "@mariozechner/pi-coding-agent": ">=0.56.1",
    "@mariozechner/pi-tui": ">=0.56.1",
    "@sinclair/typebox": "*"
  }
}

import { createHash } from "node:crypto";
import { readFile, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { Type } from "@sinclair/typebox";
import { Value } from "@sinclair/typebox/value";
import type { LinearMetadata } from "./types.ts";
import { LinearSyncError } from "./types.ts";

/**
 * TypeBox schema for LinearMetadata validation
 */
const LinearMetadataSchema = Type.Object({
	$schema: Type.Optional(Type.String()),
	version: Type.Literal("1.0"),
	featureId: Type.String({ pattern: "^\\d{3}-.+$" }),
	linear: Type.Optional(
		Type.Object({
			issueId: Type.String({ minLength: 1 }),
			issueKey: Type.String({ pattern: "^[A-Z]{2,4}-\\d+$" }),
			teamKey: Type.String({ pattern: "^[A-Z]{2,4}$" }),
			lastSync: Type.String(),
			specHash: Type.String({ pattern: "^[a-f0-9]{64}$" }),
		}),
	),
	tasks: Type.Array(
		Type.Object({
			taskId: Type.String({ pattern: "^T\\d{3}$" }),
			linearSubIssueId: Type.String({ minLength: 1 }),
			linearSubIssueKey: Type.String({ pattern: "^[A-Z]{2,4}-\\d+$" }),
			lastSync: Type.String(),
			taskHash: Type.String({ pattern: "^[a-f0-9]{64}$" }),
			isComplete: Type.Optional(Type.Boolean()),
		}),
	),
});

/**
 * Compute SHA-256 hash of content
 * @param content - Content to hash
 * @returns Hex-encoded SHA-256 hash
 */
export function computeHash(content: string): string {
	return createHash("sha256").update(content, "utf8").digest("hex");
}

