import { readFile } from "node:fs/promises";
import { join } from "node:path";
import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import type { LinearMetadata, WorkflowPaths } from "./types.ts";
import { LinearSyncError } from "./types.ts";
import {
	computeHash,
	createInitialMetadata,
	loadMetadata,
	writeMetadata,
} from "./linear-metadata.js";
import { formatSanitizationSummary, sanitizeContent } from "./linear-sanitizer.js";
import { findTaskById, parseTasks } from "./tasks-parser.js";
import {
	buildSyncStatus,
	formatSyncStatus,
	STATUS_TRANSITION_RULES,
	StatusTransitionManager,
} from "./linear-status.js";

/**
 * Linear integration coordinator for /spec extension
 */
export class LinearIntegration {
	constructor(
		private ctx: ExtensionCommandContext,
		private paths: WorkflowPaths,
		private pi: ExtensionAPI,
	) {}

	/**
	 * Queue Linear tool invocation via agent
	 * Uses pi.sendUserMessage() to prompt the agent to call linear_issue tool
	 */
	private queueLinearToolCall(params: Record<string, unknown>, description: string): void {
		// Build a prompt that asks the agent to call the linear_issue tool
		const promptParts = [
