  description: sanitized,  // ← Just sanitized, NOT template-transformed!
  team: teamKey,
};
```

**What's missing**: The transformation logic from `issue-template.md` is not implemented.

## What Actually Happens Now

Currently, the agent receives:
1. **Title**: First `#` heading from spec.md (with "Feature Specification:" prefix removed)
2. **Description**: Entire spec.md content with:
   - ✅ Absolute paths removed/relativized
   - ✅ Spec artifact references filtered out
   - ❌ **But metadata, priorities, edge cases, requirement IDs still present**

## To Implement the Template

I can add a `transformSpecContent()` function that applies the full template transformation. Would you like me to:

### Option 1: Implement Full Template Transformation

Add to `packages/spec/extension/linear-sanitizer.ts`:

```typescript
/**
 * Transform spec.md to Linear Issue format per issue-template.md
 */
export function transformSpecContent(specContent: string): string {
  let content = specContent;

  // 1. Extract title (remove "Feature Specification:" prefix)
  const titleMatch = content.match(/^#\s+(?:Feature Specification:\s*)?(.+?)$/m);

  // 2. Remove metadata block (everything between first heading and "## User Scenarios")
  content = content.replace(/^#.+?\n([\s\S]*?)\n(?=## User Scenarios)/m, '');

  // 3. Remove Clarifications section
  content = content.replace(/## Clarifications[\s\S]*?(?=##\s+[^#]|\n$)/g, '');

  // 4. Remove Edge Cases section
  content = content.replace(/## Edge Cases[\s\S]*?(?=##\s+[^#]|\n$)/g, '');

  // 5. Clean up User Stories
  content = content.replace(/\(Priority: P\d+\)/g, '');
  content = content.replace(/\*\*Why this priority\*\*:[\s\S]*?(?=\*\*Acceptance Scenarios\*\*)/g, '');
  content = content.replace(/\*\*Independent Test\*\*:[\s\S]*?(?=\*\*Acceptance Scenarios\*\*)/g, '');

  // 6. Remove (mandatory) labels
  content = content.replace(/\s*\*\(mandatory\)\*/g, '');

  // 7. Remove requirement/criterion ID prefixes
  content = content.replace(/- \*\*FR-\d+\*\*:\s*/g, '- ');
  content = content.replace(/- \*\*SC-\d+\*\*:\s*/g, '- ');

  return content;
}
```

Then update `linear.ts`:

```typescript
