/**
 * Patterns for detecting absolute paths
 */
const ABSOLUTE_PATH_PATTERNS = [
	// Unix-style absolute paths: /path/to/file.ext
	/(?:^|\s)(\/[\w\-_.\/]+\.[\w]+)/g,
	// Unix-style home directory: ~/path/to/file.ext
	/(?:^|\s)(~\/[\w\-_.\/]+\.[\w]+)/g,
	// Windows-style absolute paths: C:\path\to\file.ext or C:/path/to/file.ext
	/(?:^|\s)([A-Za-z]:[\\\/][\w\-_.\\\/]+\.[\w]+)/g,
];

/**
 * Patterns for spec workflow artifacts to filter out
 */
const ARTIFACT_PATTERNS = [
	/\bplan\.md\b/gi,
	/\btasks\.md\b/gi,
	/\bchecklist\.md\b/gi,
	/\bresearch\.md\b/gi,
	/\bdata-model\.md\b/gi,
	/\bquickstart\.md\b/gi,
	/\bcontracts\/[\w\-_.]+/gi,
	/\bchecklists\/[\w\-_.]+/gi,
	/\/spec(?:ify|clarify|plan|tasks|analyze|implement|linear)\b/gi,
	/\/speckit\.[\w]+\b/gi,
];

/**
 * Sanitize content for Linear sync by removing absolute paths and spec artifacts
 * @param content - Original markdown content
 * @param repoRoot - Optional repository root for path relativization
 * @returns Sanitized content with change tracking
 */
export function sanitizeContent(content: string, repoRoot?: string): SanitizedContent {
	const changes: ContentChange[] = [];
	let sanitized = content;

	// Phase 1: Sanitize absolute paths
	for (const pattern of ABSOLUTE_PATH_PATTERNS) {
		sanitized = sanitized.replace(pattern, (match, path) => {
			// Try to relativize if repoRoot is provided
			if (repoRoot && path.startsWith(repoRoot)) {
				const relativePath = path.substring(repoRoot.length).replace(/^\/+/, "");
				changes.push({
					type: "absolute-path-relativized",
					original: path,
					replacement: relativePath,
				});
				return match.replace(path, relativePath);
			}

			// Otherwise remove the absolute path
			changes.push({
				type: "absolute-path-removed",
				original: path,
				replacement: "",
			});
			return match.replace(path, "");
		});
	}

	// Phase 2: Filter out spec artifact references
	for (const pattern of ARTIFACT_PATTERNS) {
		sanitized = sanitized.replace(pattern, (match) => {
			changes.push({
				type: "artifact-reference-removed",
				original: match,
				replacement: "",
			});
			return "";
		});
	}

	// Cleanup: Collapse multiple consecutive spaces
	sanitized = sanitized.replace(/  +/g, " ");

	// Cleanup: Remove trailing spaces on lines
	sanitized = sanitized.replace(/ +$/gm, "");

	// Cleanup: Normalize line endings
	sanitized = sanitized.replace(/\r\n/g, "\n");

	// Cleanup: Avoid multiple consecutive blank lines
	sanitized = sanitized.replace(/\n{3,}/g, "\n\n");

	return {
		original: content,
		sanitized: sanitized.trim(),
		changes,
	};
}

/**
 * Check if content needs sanitization
 * @param content - Content to check
 * @returns True if sanitization would make changes
 */
export function needsSanitization(content: string): boolean {
	// Check for absolute paths
	for (const pattern of ABSOLUTE_PATH_PATTERNS) {
		if (pattern.test(content)) {
			return true;
		}
	}

	// Check for artifact references
	for (const pattern of ARTIFACT_PATTERNS) {
		if (pattern.test(content)) {
			return true;
		}
	}

	return false;
}

/**
 * Format sanitization changes for display
 * @param changes - List of content changes
 * @returns Human-readable summary
