import { describe, expect, it } from "vitest";
import { transformSpecContent } from "../extension/linear-sanitizer.js";

describe("transformSpecContent", () => {
	it("removes Feature Specification prefix from title", () => {
		const input = `# Feature Specification: Linear Integration

Some content here`;
		const result = transformSpecContent(input);
		expect(result).toContain("# Linear Integration");
		expect(result).not.toContain("Feature Specification:");
	});

	it("removes metadata block between title and first section", () => {
		const input = `# Feature Specification: Test Feature

**Feature Branch**: 001-test
**Created**: 2026-04-15
**Status**: Draft

## User Scenarios & Testing

Content here`;
		const result = transformSpecContent(input);
		expect(result).not.toContain("**Feature Branch**:");
		expect(result).not.toContain("**Created**:");
		expect(result).not.toContain("**Status**:");
	});

	it("removes Clarifications section entirely", () => {
		const input = `# Test Feature

## Clarifications

- Q: What about X? → A: We do Y

## User Scenarios & Testing

Content here`;
		const result = transformSpecContent(input);
		expect(result).not.toContain("## Clarifications");
		expect(result).not.toContain("Q: What about X?");
	});

	it("removes Edge Cases section entirely", () => {
		const input = `# Test Feature

## Edge Cases

- What happens when X?
  - We handle Y

## Requirements

Content here`;
		const result = transformSpecContent(input);
		expect(result).not.toContain("## Edge Cases");
		expect(result).not.toContain("What happens when X?");
	});

	it("removes (mandatory) labels from headers", () => {
		const input = `# Test Feature

## User Scenarios & Testing *(mandatory)*

### User Story 1

## Requirements *(mandatory)*

